package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class CSVPrinterTest {

    @Mock
    private Appendable out;

    @Mock
    private CSVFormat format;

    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        MockitoAnnotations.openMocks(this);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void println_AppendsRecordSeparator_WhenRecordSeparatorIsNotNull() throws IOException {
        String recordSeparator = "\n";
        when(format.getRecordSeparator()).thenReturn(recordSeparator);

        printer.println();

        verify(out).append(recordSeparator);
        // Use reflection to check private field newRecord is true
        try {
            var field = CSVPrinter.class.getDeclaredField("newRecord");
            field.setAccessible(true);
            assertTrue(field.getBoolean(printer));
        } catch (NoSuchFieldException | IllegalAccessException e) {
            fail("Reflection failed: " + e.getMessage());
        }
    }

    @Test
    void println_DoesNotAppend_WhenRecordSeparatorIsNull() throws IOException {
        when(format.getRecordSeparator()).thenReturn(null);

        printer.println();

        verify(out, never()).append(anyString());
        // Use reflection to check private field newRecord is true
        try {
            var field = CSVPrinter.class.getDeclaredField("newRecord");
            field.setAccessible(true);
            assertTrue(field.getBoolean(printer));
        } catch (NoSuchFieldException | IllegalAccessException e) {
            fail("Reflection failed: " + e.getMessage());
        }
    }

    @Test
    void println_ThrowsIOException_WhenAppendThrows() throws IOException {
        String recordSeparator = "\r\n";
        when(format.getRecordSeparator()).thenReturn(recordSeparator);
        doThrow(new IOException("append failed")).when(out).append(recordSeparator);

        IOException thrown = assertThrows(IOException.class, () -> printer.println());
        assertEquals("append failed", thrown.getMessage());
        // newRecord should not be set to true if append throws, but method sets after append
        // So newRecord is still true as per code, we verify it
        try {
            var field = CSVPrinter.class.getDeclaredField("newRecord");
            field.setAccessible(true);
            assertTrue(field.getBoolean(printer));
        } catch (NoSuchFieldException | IllegalAccessException e) {
            fail("Reflection failed: " + e.getMessage());
        }
    }
}
